; 伯爵の屋敷

name = 伯爵の屋敷２Ｆ
insideName = ２Ｆ
lower = 伯爵の屋敷１Ｆ
level = 44
bgm = bad
margin = 3
shadow = dark
sky = forest
roof = wood

; パーツ画像
━ = plaster
　 = wood
／ = door
∫ = pick
︻ = panel
㊦ = ladderd
⑶ = barrel
⑷ = barrel
⑸ = barrel
⑹ = barrel
⑦ = human
⑧ = human

; 敵情報
maxGroups = 2
monsters = ローグ,ハイウェイマン,ブッシュワッカー
traps = 石つぶて,毒針,しびれ針

; 宝箱
box[1] = ５連泊券,レオタード_u,こじあけの鍵,精神の指輪,魔法の錠前,ボム

[map]
;---------------------------------------------------------------------------------------------------------------
